package com.chimera.tools\n\nimport com.chimera.core.state.GameState\nimport com.chimera.core.state.RelationshipArchetypeEngine\nimport com.chimera.core.state.GameStateMachine\nimport kotlinx.serialization.Serializable\nimport java.io.File\nimport java.time.Instant\n\n/**\n * TimeTravel is a deterministic save-state recording and replay system for the\n * Chimera simulation engine. It captures complete simulation snapshots (ticks)\n * and supports replay, branching, undo/redo, and deterministic validation.\n *\n * Key features:\n *   • Record full engine/state snapshots after every game.tick()\n *   • Replay any recorded session with a visitor callback\n *   • Create alternative timelines (branches) from any saved tick\n *   • Undo/redo through recorded history\n *   • Deterministic state hashing for integrity validation\n *   • Checkpointing and full session persistence (JSON)\n */\nclass TimeTravel private constructor(\n    private val engine: RelationshipArchetypeEngine,\n    private val stateMachine: GameStateMachine,\n    private val initialState: GameState,\n    private val config: TimeTravelConfig = TimeTravelConfig()\n) {\n    private val sessionId: String = \"CTRS-${Instant.now().toEpochMilli()}\"\n    private val snapshots = mutableListOf<StateSnapshot>()\n    private var currentTick = 0\n    private var isRecording = false\n    private var isReplaying = false\n\n    val currentTickIndex: Int get() = currentTick\n    val isRecording: Boolean get() = isRecording\n    val isReplaying: Boolean get() = isReplaying\n    val tickCount: Int get() = snapshots.size\n\n    companion object {\n        /** Creates a recorder attached to an existing simulation. */\n        fun createRecorder(\n            engine: RelationshipArchetypeEngine,\n            stateMachine: GameStateMachine,\n            initialState: GameState,\n            config: TimeTravelConfig = TimeTravelConfig()\n        ): TimeTravel {\n            val initialSnapshot = captureState(engine, stateMachine, initialState, 0)\n            return TimeTravel(engine, stateMachine, initialState, config).apply {\n                snapshots.add(initialSnapshot)\n                isRecording = true\n            }\n        }\n\n        /** Loads a previously saved session from disk. */\n        fun loadSession(filePath: String): TimeTravel {\n            val file = File(filePath)\n            require(file.exists()) { \"Session file not found: $filePath\" }\n            val json = Json { ignoreUnknownKeys = true; isLenient = true }\n            val sessionData: SessionData = json.decodeFromString(file.readText())\n\n            val engine = RelationshipArchetypeEngine.deserialize(sessionData.relationshipEngine)\n            val stateMachine = GameStateMachine.deserialize(sessionData.stateMachineData)\n            val timeTravel = TimeTravel(engine, stateMachine, sessionData.initialState, sessionData.config)\n            timeTravel.snapshots.addAll(sessionData.snapshots)\n            timeTravel.currentTick = sessionData.currentTick\n            return timeTravel\n        }\n\n        /** Captures a snapshot of the current simulation state. */\n        internal fun captureState(\n            engine: RelationshipArchetypeEngine,\n            stateMachine: GameStateMachine,\n            state: GameState,\n            tick: Int\n        ): StateSnapshot {\n            return StateSnapshot(\n                tick = tick,\n                timestamp = Instant.now().toEpochMilli(),\n                stateHash = computeDeterministicHash(engine, stateMachine, state),\n                relationshipEngineState = RelationshipEngineSnapshot.fromEngine(engine),\n                gameStateSnapshot = GameStateSnapshot.fromState(state),\n                stateMachineSnapshot = stateMachine.captureSnapshot()\n            )\n        }\n\n        /** Deterministic hash combining all simulation-relevant state. */\n        private fun computeDeterministicHash(\n            engine: RelationshipArchetypeEngine,\n            stateMachine: GameStateMachine,\n            state: GameState\n        ): String {\n            val data = buildString {\n                append(engine.serializeForHashing())\n                append(state.serializeForHashing())\n                append(stateMachine.serializeForHashing())\n            }\n            return data.hashCode().toString(16)\n        }\n    }\n\n    /** Records one simulation tick. Must be called after each game.tick(). */\n    fun recordTick() {\n        require(isRecording) { \"Cannot record tick when not in recording mode\" }\n        currentTick++\n        val snapshot = captureState(engine, stateMachine, stateMachine.currentState, currentTick)\n        snapshots.add(snapshot)\n        if (config.maxHistorySize > 0 && snapshots.size > config.maxHistorySize) {\n            snapshots.removeAt(0)\n            currentTick = snapshots.size - 1\n        }\n    }\n\n    /** Replays the entire recorded session via visitor callback. */\n    fun replay(visitor: (StateSnapshot, Int) -> Unit) {\n        require(!isReplaying) { \"Already replaying\" }\n        isReplaying = true\n        try {\n            snapshots.forEachIndexed(visitor)\n        } finally {\n            isReplaying = false\n        }\n    }\n\n    /** Rewinds to a specific tick and restores that state. */\n    fun rewindTo(tick: Int): GameState {\n        require(tick in 0..<snapshots.size) { \"Tick $tick out of range [0, ${snapshots.size})\" }\n        currentTick = tick\n        return restoreState(snapshots[tick])\n    }\n\n    /** Creates a branch (alternative timeline) from the current state. */\n    fun createBranchAt(tick: Int): TimeTravel {\n        require(tick in 0..<snapshots.size) { \"Tick $tick out of range [0, ${snapshots.size})\" }\n        val branchState = snapshots[tick]\n        val restoredState = restoreState(branchState)\n\n        return TimeTravel(\n            engine = this.engine,\n            stateMachine = this.stateMachine,\n            initialState = restoredState,\n            config = this.config\n        ).apply {\n            snapshots.addAll(this@TimeTravel.snapshots.take(tick + 1))\n            currentTick = tick\n            isRecording = this@TimeTravel.isRecording\n        }\n    }\n\n    /** Steps back one tick (undo). */\n    fun undo(): GameState? {\n        if (currentTick <= 0) return null\n        return rewindTo(currentTick - 1)\n    }\n\n    /** Steps forward one tick (redo). */\n    fun redo(): GameState? {\n        if (currentTick >= snapshots.size - 1) return null\n        return rewindTo(currentTick + 1)\n    }\n\n    /** Saves the current session to disk as JSON. */\n    fun saveSession(filePath: String) {\n        val sessionData = SessionData(\n            sessionId = sessionId,\n            config = config,\n            initialState = initialState,\n            relationshipEngine = RelationshipEngineSnapshot.toEngine(engine),\n            stateMachineData = stateMachine.serializeForPersistence(),\n            currentTick = currentTick,\n            snapshots = snapshots\n        )\n        val json = Json { ignoreUnknownKeys = true; isLenient = true; prettyPrint = true }\n        val directory = File(filePath).parentFile\n        if (directory != null && !directory.exists()) directory.mkdirs()\n        File(filePath).writeText(json.encodeToString(sessionData))\n    }\n\n    /** Saves a checkpoint (partial state) for quick restoration. */\n    fun saveCheckpoint(label: String): String {\n        val checkpointDir = File(config.checkpointDir).apply { mkdirs() }\n        val filePath = File(checkpointDir, \"${sessionId}_$label.chk\").absolutePath\n        saveSession(filePath)\n        return filePath\n    }\n\n    /** Loads a checkpoint previously saved with [saveCheckpoint]. */\n    companion object {\n        fun loadCheckpoint(label: String, sessionId: String): TimeTravel? {\n            val filePath = File(config.checkpointDir, \"${sessionId}_$label.chk\").absolutePath\n            return if (File(filePath).exists()) loadSession(filePath) else null\n        }\n    }\n\n    /** Debug utilities for time-travel debugging. */\n    object Debug {\n        /** Dumps a human-readable timeline of all recorded ticks. */\n        fun dumpTimeline(timeTravel: TimeTravel): String {\n            val sb = StringBuilder()\n            sb.appendLine(\"TimeTravel Session: ${timeTravel.sessionId}\")\n            sb.appendLine(\"Total ticks: ${timeTravel.tickCount}\")\n            sb.appendLine(\"Current tick: ${timeTravel.currentTickIndex}\")\n            sb.appendLine(\"Recording: ${timeTravel.isRecording}\")\n            sb.appendLine(\"Replaying: ${timeTravel.isReplaying}\")\n            sb.appendLine(\"=\".repeat(60))\n\n            timeTravel.snapshots.forEachIndexed { index, snapshot ->\n                val marker = when {\n                    index == timeTravel.currentTickIndex -> \"(*) CURRENT\"\n                    index < timeTravel.currentTickIndex -> \"(-) past\"\n                    else -> \"(?) future (branch)\"\n                }\n                sb.appendLine(\"[Tick ${snapshot.tick}] $marker\")\n                sb.appendLine(\"  Hash: ${snapshot.stateHash.take(8)}\")\n                sb.appendLine(\"  State: ${snapshot.gameStateSnapshot}\")\n                sb.appendLine(\"  Engine: ${snapshot.relationshipEngineState.summary()}\")\n            }\n            return sb.toString()\n        }\n\n        /** Validates deterministic integrity of a session. */\n        fun validateSession(timeTravel: TimeTravel): ValidationResult {\n            val issues = mutableListOf<String>()\n            for (i in 1..<timeTravel.snapshots.size) {\n                val prev = timeTravel.snapshots[i - 1]\n                val curr = timeTravel.snapshots[i]\n                if (curr.tick != prev.tick + 1) {\n                    issues.add(\"Tick sequence broken at index $i\")\n                }\n                if (prev.stateHash == curr.stateHash && curr.tick != timeTravel.currentTickIndex) {\n                    issues.add(\"Identical state hash at non-current tick $curr.tick\")\n                }\n            }\n            return ValidationResult(\n                isValid = issues.isEmpty(),\n                issues = issues,\n                totalTicks = timeTravel.tickCount,\n                deterministic = timeTravel.snapshots.all { it.stateHash.isNotBlank() }\n            )\n        }\n    }\n}\n\n/** Configuration for TimeTravel behavior. */\ndata class TimeTravelConfig(\n    val maxHistorySize: Int = 0,\n    val checkpointDir: String = \"checkpoints\",\n    val compressSnapshots: Boolean = true,\n    val deterministicMode: Boolean = true\n)\n\n/** Snapshot of the simulation state at a specific tick. */\n@Serializable\ndata class StateSnapshot(\n    val tick: Int,\n    val timestamp: Long,\n    val stateHash: String,\n    val relationshipEngineState: RelationshipEngineSnapshot,\n    val gameStateSnapshot: GameStateSnapshot,\n    val stateMachineSnapshot: StateMachineSnapshot\n)\n\n/** Serializable snapshot of the relationship archetype engine. */\n@Serializable\ndata class RelationshipEngineSnapshot(\n    val archetypeData: Map<String, ArchetypeState>,\n    val interactionGraph: Map<String, List<String>>,\n    val configuration: Map<String, Any>\n) {\n    companion object {\n        fun fromEngine(engine: RelationshipArchetypeEngine): RelationshipEngineSnapshot {\n            return RelationshipEngineSnapshot(\n                archetypeData = engine.archetypes.mapValues { it.value.serialize() },\n                interactionGraph = engine.interactionGraph,\n                configuration = engine.configuration\n            )\n        }\n\n        fun toEngine(snapshot: RelationshipEngineSnapshot): RelationshipArchetypeEngine {\n            val engine = RelationshipArchetypeEngine(snapshot.configuration)\n            engine.archetypes.putAll(\n                snapshot.archetypeData.mapValues { (_, state) ->\n                    RelationshipArchetypeEngine.deserializeArchetype(state)\n                }\n            )\n            engine.interactionGraph.putAll(snapshot.interactionGraph)\n            return engine\n        }\n\n        fun summary(snapshot: RelationshipEngineSnapshot): String {\n            return \"Archetypes: ${snapshot.archetypeData.size}, Interactions: ${snapshot.interactionGraph.size}\"\n        }\n    }\n}\n\n/** Serializable snapshot of the game state. */\n@Serializable\ndata class GameStateSnapshot(\n    val playerId: String,\n    val npcStates: Map<String, NpcState>,\n    val worldState: Map<String, Any>,\n    val flags: Map<String, Boolean>,\n    val timers: Map<String, Long>\n)\n\n/** Serializable snapshot of the game state machine. */\n@Serializable\ndata class StateMachineSnapshot(\n    val currentState: String,\n    val pendingTransitions: List<String>,\n    val history: List<String>,\n    val variables: Map<String, Any>\n)\n\n/** Serializable wrapper for the entire session. */\n@Serializable\ndata class SessionData(\n    val sessionId: String,\n    val config: TimeTravelConfig,\n    val initialState: GameState,\n    val relationshipEngine: RelationshipEngineSnapshot,\n    val stateMachineData: StateMachineSnapshot,\n    val currentTick: Int,\n    val snapshots: List<StateSnapshot>\n)\n\n/** Result of session validation. */\ndata class ValidationResult(\n    val isValid: Boolean,\n    val issues: List<String>,\n    val totalTicks: Int,\n    val deterministic: Boolean\n)\n\n/** Example usage and demonstration of time-travel capabilities. */\nfun main() {\n    println(\"Chimera Time-Travel Debugging System\")\n    println(\"=\".repeat(60))\n\n    // Simulate creating initial game state and engines\n    val initialState = GameState(\n        playerId = \"player_1\",\n        npcStates = mapOf(\"npc_001\" to NpcState(\"friendly\", 100, mapOf(\"trust\" to 50))),\n        worldState = mapOf(\"location\" to \"village\", \"time\" to \"day\"),\n        flags = mapOf(\"quest_started\" to false),\n        timers = mapOf(\"day_cycle\" to 0)\n    )\n\n    val engine = RelationshipArchetypeEngine(mapOf(\"default\" to emptyMap()))\n    val stateMachine = GameStateMachine(initialState)\n\n    // Create a time-travel recorder\n    val timeTravel = TimeTravel.createRecorder(engine, stateMachine, initialState).apply {\n        // Simulate some game ticks\n        for (i in 1..5) {\n            stateMachine.tick()  // Advance simulation\n            recordTick()          // Record the state\n        }\n    }\n\n    println(\"Recorded ${timeTravel.tickCount} ticks\")\n    println(\"Current tick: ${timeTravel.currentTickIndex}\")\n\n    // Save the session for later replay\n    val sessionPath = \"chimera_session.ctr\"\n    timeTravel.saveSession(sessionPath)\n    println(\"Session saved to: $sessionPath\")\n\n    // Load and replay the session\n    println(\"\\n--- Replaying Session ---\")\n    val replay = TimeTravel.loadSession(sessionPath)\n    replay.replay { snapshot, index ->\n        println(\"Tick ${snapshot.tick}: hash=${snapshot.stateHash.take(8)}...\")\n    }\n\n    // Demonstrate branching and time-travel\n    println(\"\\n--- Creating Branch from Tick 2 ---\")\n    val branch = replay.createBranchAt(2)\n    println(\"Branch created at tick ${branch.currentTickIndex}\")\n\n    // Demonstrate undo/redo\n    println(\"\\n--- Undo/Redo Demo ---\")\n    println(\"Before undo: tick ${replay.currentTickIndex}\")\n    replay.undo()\n    println(\"After undo: tick ${replay.currentTickIndex}\")\n    replay.redo()\n    println(\"After redo: tick ${replay.currentTickIndex}\")\n\n    // Validate session integrity\n    println(\"\\n--- Session Validation ---\")\n    val validation = TimeTravel.Debug.validateSession(replay)\n    println(\"Valid: ${validation.isValid}\")\n    println(\"Deterministic: ${validation.deterministic}\")\n    if (validation.issues.isNotEmpty()) {\n        println(\"Issues: ${validation.issues.joinToString(\", \")}\")\n    }\n\n    // Generate timeline debug output\n    println(\"\\n--- Timeline Debug Output ---\")\n    println(TimeTravel.Debug.dumpTimeline(replay))\n\n    println(\"\\nTime-travel debugging demonstration complete!\")\n}\n\n// Stub classes to support the implementation\nclass GameState(\n    val playerId: String,\n    val npcStates: Map<String, NpcState>,\n    val worldState: Map<String, Any>,\n    val flags: Map<String, Boolean>,\n    val timers: Map<String, Long>\n)\n\ndata class NpcState(\n    val archetype: String,\n    val health: Int,\n    val relationships: Map<String, Int>\n)\n\nclass RelationshipArchetypeEngine(\n    configuration: Map<String, Any> = mapOf()\n) {\n    val archetypes: MutableMap<String, Any> = mutableMapOf()\n    val interactionGraph: MutableMap<String, List<String>> = mutableMapOf()\n\n    fun serialize(): Map<String, Any> = mapOf(\"data\" to \"serialized\")\n\n    companion object {\n        fun deserialize(data: Map<String, Any>): RelationshipArchetypeEngine {\n            return RelationshipArchetypeEngine(data)\n        }\n    }\n}"}}